#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <algorithm>

// This driver is illustrative. It shows the conceptual flow.
// For a real evaluation, an external system would:
// 1. Compile the student's <file_number>.cpp into an executable.
// 2. For each test case:
//    a. Provide the "input" string to the executable's stdin.
//    b. Capture the executable's stdout.
//    c. Compare the captured stdout with the "expected" string.

// Helper to generate expected output (for driver's own reference)
std::string generate_expected(const std::string& input_str) {
    std::istringstream iss(input_str);
    std::vector<int> nums;
    int n;
    while (iss >> n) {
        nums.push_back(n);
    }
    std::sort(nums.begin(), nums.end());
    std::ostringstream oss;
    for (size_t i = 0; i < nums.size(); ++i) {
        oss << nums[i] << (i == nums.size() - 1 ? "" : " ");
    }
    return oss.str();
}

int main() {
    std::cout << "Driver is conceptual. See comments for actual testing method." << std::endl;
    std::cout << "Example test case: Input '30 10 20'" << std::endl;
    std::cout << "Expected output:   '" << generate_expected("30 10 20") << "'" << std::endl;
    return 0;
}
